async function processDueNotifications(env2, meta = {}) {
  const settings = await sbGetNotificationSettings(env2);
  const queueSetting = settings.scheduled_queue || mergeNotificationSetting("scheduled_queue");
  if (queueSetting.enabled === false) {
    return {
      ok: true,
      source: meta.source || "manual",
      total_due: 0,
      sent: 0,
      failed: 0,
      skipped: 0,
      errors: [],
      note: "scheduled queue disabled"
    };
  }
  let dueJobs;
  try {
    dueJobs = await sbGetDueJobs(env2, 50);
  } catch (error) {
    if (sbMissingTable(error, "notification_jobs")) {
      return {
        ok: true,
        source: meta.source || "manual",
        total_due: 0,
        sent: 0,
        failed: 0,
        skipped: 0,
        errors: [],
        note: "notification_jobs table missing"
      };
    }
    throw error;
  }
  const result = {
    ok: true,
    source: meta.source || "manual",
    total_due: Array.isArray(dueJobs) ? dueJobs.length : 0,
    sent: 0,
    failed: 0,
    skipped: 0,
    errors: []
  };
  if (!Array.isArray(dueJobs) || dueJobs.length === 0) {
    return result;
  }
  for (const job of dueJobs) {
    try {
      const claimed = await sbClaimJob(env2, job);
      if (!claimed) {
        result.skipped += 1;
        continue;
      }
      const textToSend = renderNotificationText(job);
      await tgSendMessage(env2, job.user_id, textToSend);
      await sbMarkJobSent(env2, job.id);
      await sbInsertNotificationLog(env2, {
        setting_key: "scheduled_queue",
        user_id: job.user_id,
        job_id: job.id,
        status: "sent",
        message_text: textToSend,
        sent_at: isoNow(),
        meta: { type: job.type || "custom", scheduled_for: job.scheduled_for || null }
      });
      await sbTouchNotificationSetting(env2, "scheduled_queue", { last_sent_at: isoNow() });
      result.sent += 1;
    } catch (error) {
      result.failed += 1;
      result.errors.push({
        id: job.id,
        error: error?.message || String(error)
      });
      try {
        await sbMarkJobFailed(env2, job.id, error?.message || String(error));
        await sbInsertNotificationLog(env2, {
          setting_key: "scheduled_queue",
          user_id: job.user_id,
          job_id: job.id,
          status: "failed",
          message_text: renderNotificationText(job),
          error_text: error?.message || String(error),
          sent_at: isoNow(),
          meta: { type: job.type || "custom", scheduled_for: job.scheduled_for || null }
        });
      } catch (patchError) {
        result.errors.push({
          id: job.id,
          error: `Mark failed error: ${patchError?.message || String(patchError)}`
        });
      }
    }
  }
  return result;
}
